using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF Core 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so keep the old property name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF Core 9 uses only the raw key for "id" (e.g. "1").
            // Existing documents use "Blog|1" format, so preserve the legacy id factory.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes via EF Core;
            // HasIndex was silently ignored before but now throws.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

}

