class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF Core 9 uses sync-over-async for Cosmos, which can
        // deadlock. Use async APIs instead.
        RunAsync(context).GetAwaiter().GetResult();
    }

    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }

    // Breaking change 5: Raw SQL queries referencing "Discriminator" must be updated
    // if you did NOT apply the HasJsonPropertyName("Discriminator") fix above.
    // With the fix applied, existing queries like:
    //   SELECT * FROM c WHERE c.Discriminator = 'Blog'
    // continue to work unchanged.
}

